9	/**
10	 * A memory region in the range of `[base_address, end_address)`.
11	 * The constructor takes an inclusive end address and stores it as exclusive.
12	 * e.g. memory_region(0x80000000, 0x8fffffff) stores base=0x80000000,
13	 *      end=0x90000000.
14	 */
15	struct MemoryRegion
16	{
17	  using addr_type = uint64_t;
18	
19	  const addr_type base_address; // inclusive
20	  const addr_type end_address; // exclusive (stored as param + 1)
21	
22	  /**
23	   * @param base_address The base address of the memory region (inclusive).
24	   * @param end_address The end address of the memory region (inclusive).
25	   * @throws std::invalid_argument if base_address > end_address.
26	   * @example memory_region(0x00, 0xff) represents [0x00, 0x100)
27	   */
28	  MemoryRegion(const addr_type base_address, const addr_type end_address)
29	      : base_address{base_address}, end_address{end_address + 1}
30	  {
31	    if (base_address > end_address)
32	      throw std::invalid_argument(std::format(
33	        "invalid memory region: [{:#x}-{:#x}]", base_address, end_address));
34	  }
35	
36	  auto contains(const addr_type addr) const noexcept -> bool
37	  {
38	    return addr >= this->base_address && addr < this->end_address;
39	  }
40	
41	  auto contains(const MemoryRegion& other) const noexcept -> bool
42	  {
43	    return other.base_address >= this->base_address
44	        && other.end_address <= this->end_address;
45	  }
46	
47	  auto overlaps(const MemoryRegion& other) const noexcept -> bool
48	  {
49	    return this->end_address > other.base_address
50	        && this->base_address < other.end_address;
51	  }
52	};
