15	// Owns a host file mapped into memory and exposes it as std::span<uint8_t>.
16	class MmapBacking
17	{
18	public:
19	  MmapBacking(const std::string& path, std::size_t size) : size_(size)
20	  {
21	    fd_ = ::open(path.c_str(), O_RDWR | O_CREAT, 0600);
22	    if (fd_ < 0)
23	      throw std::runtime_error("MmapBacking: open(" + path
24	                               + ") failed: " + std::strerror(errno));
25	    if (::ftruncate(fd_, static_cast<off_t>(size_)) != 0) {
26	      auto err = std::strerror(errno);
27	      ::close(fd_);
28	      fd_ = -1;
29	      throw std::runtime_error("MmapBacking: ftruncate failed: "
30	                               + std::string{err});
31	    }
32	    // MAP_POPULATE prefaults pages so the first sweep of writes (e.g. ELF
33	    // loading) does not stall on per-page faults.
34	    void* p = ::mmap(nullptr, size_, PROT_READ | PROT_WRITE,
35	                     MAP_SHARED | MAP_POPULATE, fd_, 0);
36	    if (p == MAP_FAILED) {
37	      auto err = std::strerror(errno);
38	      ::close(fd_);
39	      fd_ = -1;
40	      throw std::runtime_error("MmapBacking: mmap failed: " + std::string{err});
41	    }
42	    base_ = static_cast<uint8_t*>(p);
43	  }
44	
45	  ~MmapBacking()
46	  {
47	    if (base_ != nullptr)
48	      ::munmap(base_, size_);
49	    if (fd_ >= 0)
50	      ::close(fd_);
51	  }
52	
53	  MmapBacking(const MmapBacking&) = delete;
54	  MmapBacking& operator=(const MmapBacking&) = delete;
55	  MmapBacking(MmapBacking&&) = delete;
56	  MmapBacking& operator=(MmapBacking&&) = delete;
57	
58	  auto span() -> std::span<uint8_t> { return {base_, size_}; }
59	
60	private:
61	  int fd_ = -1;
62	  uint8_t* base_ = nullptr;
63	  std::size_t size_ = 0;
64	};
