337	        "--kanata-loop-start and --kanata-loop-end must be specified together");
338	    if (args.kanata_loop_start.has_value()) {
339	      if (args.kanata_file.empty() && args.clarity_file.empty())
340	        throw std::runtime_error(
341	          "--kanata-loop-* requires --kanata or --clarity");
342	      if (args.kanata_loop_record == 0)
343	        throw std::runtime_error("--kanata-loop-record must be >= 1");
344	      loop_gate = kanata::LoopGate{*args.kanata_loop_start,
345	                                   *args.kanata_loop_end,
346	                                   args.kanata_loop_skip,
347	                                   args.kanata_loop_record};
348	    }
349	
350	    if (!args.kanata_file.empty())
351	      sim.enable_kanata(args.kanata_file, args.objdump_file, loop_gate);
352	
353	    if (!args.clarity_file.empty())
354	      sim.enable_clarity(args.clarity_file, args.objdump_file, loop_gate);
355	
356	    if (!args.elf_file.empty() && !args.continue_ctx)
357	      sim.load_elf(args.elf_file);
358	
359	    // Apply per-hart reset vector overrides (after load_elf sets defaults)
360	    for (const auto& s: args.reset_vectors) {
361	      auto [hart, addr] = parse_reset_vector(s);
362	      if (hart) {
363	        sim.set_reset_vector(*hart, addr);
364	      } else {
365	        for (size_t i = 0; i < sim.platform.reset_vector.size(); ++i)
366	          sim.set_reset_vector(i, addr);
367	      }
368	    }
369	
370	    if (args.continue_ctx)
371	      spdlog::info("You're resuming program from the given context");
372	
373	    if (args.jtag_port)
374	      sim.init_debug_port(args.jtag_port.value());
375	
376	    if (!args.jtag_port && args.elf_file.empty() && !args.continue_ctx
377	        && args.resume_from_qemu.empty())
378	      throw std::runtime_error(
379	        "Required arg : program, --jtag-port, or --resume-from-qemu");
380	
381	    if (args.continue_ctx || args.save_ctx) {
382	      std::string_view s = args.context_dir;
383	      if (std::filesystem::exists(s) && !std::filesystem::is_directory(s))
384	        throw std::runtime_error("Error: Path " + std::string{s}
385	                                 + " exists but is not a directory.");
386	      if (!std::filesystem::exists(s)) {
387	        try {
388	          std::filesystem::create_directories(s);
389	        } catch (const std::filesystem::filesystem_error& e) {
390	          throw std::runtime_error(std::string{"Failed to create directory: "}
391	                                   + e.what());
392	        }
393	      }
394	      sim.context_config = {args.save_ctx, args.continue_ctx, args.context_dir};
395	    }
396	
397	    sim.reset();
398	
399	    if (!args.resume_from_qemu.empty())
400	      sim.apply_resume_from_qemu(args.resume_from_qemu);

